# -*- coding: utf-8 -*-
"""Write all 8 local_005 and local_006 human translation JSON files."""
import json
import sys
from pathlib import Path

OUT = Path(r"c:\apps\hehehe\be-a-tzaddik\data\translation-catalog\human")
TOOLS = Path(__file__).resolve().parent


def write_json(name: str, key: str, strings: list) -> None:
    path = OUT / name
    path.write_text(
        json.dumps({key: strings}, ensure_ascii=False, indent=2) + "\n",
        encoding="utf-8",
    )


def load_py_arrays(module_name: str, *names: str) -> dict:
    ns = {"__builtins__": __builtins__}
    src = (TOOLS / module_name).read_text(encoding="utf-8")
    # Strip side-effect writes from helper modules
    lines = []
    for line in src.splitlines():
        if line.strip().startswith("OUT.write_text"):
            continue
        if line.strip().startswith('print(') and "wrote" in line:
            continue
        if line.strip().startswith("assert len(HE)"):
            continue
        if line.strip().startswith("bad_count") or line.strip().startswith("for i, s in enumerate(HE"):
            break
        lines.append(line)
    exec("\n".join(lines), ns)
    return {n: ns[n] for n in names}


