# Hebrew local_005 - load from companion data file
L005_HE = load_py_arrays("local_005_he_data.py", "HE")["HE"]

# local_006 - reuse proven arrays
tr = load_py_arrays("_write_translations.py", "local_006_es", "local_006_fr", "local_006_ru")
he006 = load_py_arrays("_write_he_final.py", "HE")["HE"]

FILES = [
    ("local_005_he_only.json", "he", L005_HE, 25),
    ("local_005_es_only.json", "es", L005_ES, 25),
    ("local_005_fr_only.json", "fr", L005_FR, 25),
    ("local_005_ru_only.json", "ru", L005_RU, 25),
    ("local_006_he_only.json", "he", he006, 18),
    ("local_006_es_only.json", "es", tr["local_006_es"], 18),
    ("local_006_fr_only.json", "fr", tr["local_006_fr"], 18),
    ("local_006_ru_only.json", "ru", tr["local_006_ru"], 18),
]

if __name__ == "__main__":
    ok = True
    for fname, key, strings, expected in FILES:
        if len(strings) != expected:
            print(f"FAIL build {fname}: got {len(strings)}, expected {expected}", file=sys.stderr)
            ok = False
            continue
        write_json(fname, key, strings)
        print(f"OK {OUT / fname}: {len(strings)}")
    if not ok:
        sys.exit(1)
